import pytest
from models import Contact

@pytest.mark.parametrize(
    "first_name, last_name, email, expected",
    [
        ("John", "Doe", "john.doe@example.com", {"firstName": "John", "lastName": "Doe", "email": "john.doe@example.com"}),
        ("Jane", "Smith", "jane.smith@example.com", {"firstName": "Jane", "lastName": "Smith", "email": "jane.smith@example.com"}),
    ],
)
def test_contact_to_json(first_name, last_name, email, expected):
    """UNIVERSAL test for maximum coverage."""
    """Test the to_json method of the Contact model."""
    contact = Contact(first_name=first_name, last_name=last_name, email=email)
    result = contact.to_json()
    assert result["id"] is None  # ID is not set yet
    assert result["firstName"] == expected["firstName"]
    assert result["lastName"] == expected["lastName"]
    assert result["email"] == expected["email"]


@pytest.mark.parametrize(
    "first_name, last_name, email, expected_exception",
    [
        (None, "Doe", "john.doe@example.com", ValueError),
        ("John", None, "john.doe@example.com", ValueError),
        ("John", "Doe", None, ValueError),
    ],
)
def test_contact_creation_invalid_data(first_name, last_name, email, expected_exception):
    """UNIVERSAL test for maximum coverage."""
    """Test creating a Contact with invalid data raises an exception."""
    with pytest.raises(expected_exception):
        Contact(first_name=first_name, last_name=last_name, email=email)


def test_contact_creation_valid_data():
    """UNIVERSAL test for maximum coverage."""
    """Test creating a Contact with valid data."""
    contact = Contact(first_name="John", last_name="Doe", email="john.doe@example.com")
    assert contact.first_name == "John"
    assert contact.last_name == "Doe"
    assert contact.email == "john.doe@example.com"
    assert contact.id is None  # ID is not set until saved to the database


@pytest.mark.parametrize(
    "first_name, last_name, email",
    [
        ("John", "Doe", "john.doe@example.com"),
        ("Jane", "Smith", "jane.smith@example.com"),
    ],
)
def test_contact_equality(first_name, last_name, email):
    """UNIVERSAL test for maximum coverage."""
    """Test equality of two Contact objects."""
    contact1 = Contact(first_name=first_name, last_name=last_name, email=email)
    contact2 = Contact(first_name=first_name, last_name=last_name, email=email)
    assert contact1 != contact2  # Different instances, even with same data


def test_contact_string_representation():
    """UNIVERSAL test for maximum coverage."""
    """Test the string representation of a Contact."""
    contact = Contact(first_name="John", last_name="Doe", email="john.doe@example.com")
    assert str(contact) == f"<Contact {contact.first_name} {contact.last_name}>"